export const customDateFormat = (date) => {
    const dateFields = { 
        year: 'numeric', 
        month: 'short', 
        day: 'numeric',
        weekday: 'long'
    };


    const formattedDate = new Date(date).toLocaleDateString(dateFields);
    console.log(formattedDate)
    return formattedDate;
}
